interface State { handle(ctx: Door): void }
class Closed implements State {
  handle(ctx: Door) { console.log('opening'); ctx.state = new Open() }
}
class Open implements State { handle(ctx: Door) { console.log('closing'); ctx.state = new Closed() } }
class Door {
  state: State = new Closed()
  request() { this.state.handle(this) }
}

enum Status { Pending, Paid, Shipped }
class Order {
  status: Status
  nextStep() {
    switch (this.status) {
      case Status.Pending: // do A; break
      case Status.Paid: // do B; break
      case Status.Shipped: // do C; break
    }
  }
}

// Version A: Single class with many conditionals
class OrderA {
  status: 'pending'|'paid'|'shipped'
  next() {
    if (this.status === 'pending') { /* do A */ this.status = 'paid' }
    else if (this.status === 'paid') { /* do B */ this.status = 'shipped' }
    else if (this.status === 'shipped') { /* do C */ }
  }
  refund() {
    switch (this.status) { /* different refund logic per status */ }
  }
}

// Version B: Context delegates to small state objects
interface OrderState { next(ctx: OrderB): void; refund(ctx: OrderB): void }
class Pending implements OrderState { next(ctx: OrderB){ ctx.state = new Paid() } refund(ctx: OrderB){ /* pending refund */ } }
class Paid implements OrderState { next(ctx: OrderB){ ctx.state = new Shipped() } refund(ctx: OrderB){ /* paid refund */ } }
class OrderB {
  state: OrderState = new Pending()
  next(){ this.state.next(this) }
  refund(){ this.state.refund(this) }
}
